#include<bits/stdc++.h>
using namespace std;
int t[200010],a[200010],ans[200010];
int main()
{
    int n,x;
    scanf("%d%d",&n,&x);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&t[i],&a[i]);
    }
    for(int i=0;i<=30;i++)
    {
        int sum=((x&(1<<i))!=0),a=-1,b=0;
        for(int j=1;j<=n;j++)
        {
            int y=((::a[j]&(1<<i))!=0);
            if(t[j]==1)
            {
                sum&=y;
                if(!y)
                {
                    a=b=0;
                }
            }
            if(t[j]==2)
            {
                sum|=y;
                if(y)
                {
                    a=1;
                    b=0;
                }
            }
            if(t[j]==3)
            {
                if(y)
                {
                    b++;
                }
            }
            b%=2;
            if(a!=-1)
            {
                sum=a;
            }
            if(b)
            {
                sum^=1;
            }
            if(sum)
            {
                ans[j]+=(1<<i);
            }
        }
    }
    for(int i=1;i<=n;i++)
    {
        printf("%d\n",ans[i]);
    }
    return 0;
}
